
param(
    [ValidateSet("cliente","tecnico")]
    [string]$Modo = "cliente",
    [string]$Tecnico = "PCLAF",
    [int]$MesesMantenimiento = 6,
    [switch]$SistemaInstaladoPorPCLAF
)

[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
$OutputEncoding = [System.Text.Encoding]::UTF8
$ErrorActionPreference = "SilentlyContinue"

$ScriptVersion = "2.4"
$BasePath = Split-Path -Parent $MyInvocation.MyCommand.Path
$FechaReporte = Get-Date -Format "yyyy-MM-dd_HH-mm-ss"
$LogoBase64 = ""

function Update-Stage {
    param([int]$Percent,[string]$Message)
    Write-Progress -Activity "PCLAF Diagnostico" -Status $Message -PercentComplete $Percent
    Write-Host ("[{0}] {1}" -f ($Percent.ToString().PadLeft(3) + "%"), $Message) -ForegroundColor DarkCyan
}

function Safe-Value {
    param($Value, [string]$Default = "N/D")
    if ($null -eq $Value -or $Value -eq "") { return $Default }
    return $Value
}

function To-DT {
    param($CimDate)
    try { if ($CimDate) { return [Management.ManagementDateTimeConverter]::ToDateTime($CimDate) } } catch {}
    return $CimDate
}

function Get-OsInfo {
    $os = $null; $cv = $null
    try { $os = Get-CimInstance Win32_OperatingSystem } catch {}
    try { $cv = Get-ItemProperty "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion" } catch {}
    [PSCustomObject]@{
        Equipo         = $env:COMPUTERNAME
        Usuario        = $env:USERNAME
        SO             = if ($cv -and $cv.ProductName) { $cv.ProductName } elseif ($os -and $os.Caption) { $os.Caption } else { "N/D" }
        Version        = if ($cv -and $cv.DisplayVersion) { $cv.DisplayVersion } else { "N/D" }
        Build          = if ($os -and $os.BuildNumber) { $os.BuildNumber } else { "N/D" }
        Arquitectura   = if ($os -and $os.OSArchitecture) { $os.OSArchitecture } else { "N/D" }
        InstaladoDesde = if ($os) { To-DT $os.InstallDate } else { "N/D" }
        UltimoArranque = if ($os) { To-DT $os.LastBootUpTime } else { "N/D" }
        Fabricante     = if ($os -and $os.Manufacturer) { $os.Manufacturer } else { "N/D" }
        SerialSO       = if ($os -and $os.SerialNumber) { $os.SerialNumber } else { "N/D" }
    }
}

function Get-SystemSummary {
    $cs = $null; $bios = $null; $board = $null; $cpu = $null; $ramModules = $null
    try { $cs = Get-CimInstance Win32_ComputerSystem } catch {}
    try { $bios = Get-CimInstance Win32_BIOS } catch {}
    try { $board = Get-CimInstance Win32_BaseBoard } catch {}
    try { $cpu = Get-CimInstance Win32_Processor | Select-Object -First 1 } catch {}
    try { $ramModules = Get-CimInstance Win32_PhysicalMemory } catch {}

    $totalRamGB = "N/D"
    try {
        if ($ramModules) {
            $sumCap = ($ramModules | Measure-Object -Property Capacity -Sum).Sum
            if ($sumCap) { $totalRamGB = [math]::Round(($sumCap / 1GB), 2) }
            elseif ($cs -and $cs.TotalPhysicalMemory) { $totalRamGB = [math]::Round(($cs.TotalPhysicalMemory / 1GB), 2) }
        } elseif ($cs -and $cs.TotalPhysicalMemory) {
            $totalRamGB = [math]::Round(($cs.TotalPhysicalMemory / 1GB), 2)
        }
    } catch {
        if ($cs -and $cs.TotalPhysicalMemory) { $totalRamGB = [math]::Round(($cs.TotalPhysicalMemory / 1GB), 2) }
    }

    [PSCustomObject]@{
        Fabricante     = if ($cs -and $cs.Manufacturer) { $cs.Manufacturer } else { "N/D" }
        Modelo         = if ($cs -and $cs.Model) { $cs.Model } else { "N/D" }
        CPU            = if ($cpu -and $cpu.Name) { ($cpu.Name -replace '\s+', ' ').Trim() } else { "N/D" }
        Cores          = if ($cpu -and $cpu.NumberOfCores) { $cpu.NumberOfCores } else { "N/D" }
        Hilos          = if ($cpu -and $cpu.NumberOfLogicalProcessors) { $cpu.NumberOfLogicalProcessors } else { "N/D" }
        RAM_Total_GB   = $totalRamGB
        Slots_RAM      = if ($ramModules) { ($ramModules | Measure-Object).Count } else { "N/D" }
        BIOS_Version   = if ($bios -and $bios.SMBIOSBIOSVersion) { ($bios.SMBIOSBIOSVersion -join ", ") } else { "N/D" }
        BIOS_Fecha     = if ($bios) { To-DT $bios.ReleaseDate } else { "N/D" }
        Motherboard    = if ($board) { "$(Safe-Value $board.Manufacturer) $(Safe-Value $board.Product)" } else { "N/D" }
        NroSerieEquipo = if ($bios -and $bios.SerialNumber) { $bios.SerialNumber } else { "N/D" }
    }
}

function Get-GpuInfo {
    try {
        $gpus = Get-CimInstance Win32_VideoController
        if (-not $gpus) { return [PSCustomObject]@{ GPU="No detectada"; VRAM_GB="N/D"; DriverVersion="N/D"; Resolution="N/D" } }
        $gpus | ForEach-Object {
            [PSCustomObject]@{
                GPU           = Safe-Value $_.Name
                VRAM_GB       = if ($_.AdapterRAM) { [math]::Round(($_.AdapterRAM / 1GB), 2) } else { "N/D" }
                DriverVersion = Safe-Value $_.DriverVersion
                Resolution    = if ($_.CurrentHorizontalResolution -and $_.CurrentVerticalResolution) { "$($_.CurrentHorizontalResolution)x$($_.CurrentVerticalResolution)" } else { "N/D" }
            }
        }
    } catch {
        [PSCustomObject]@{ GPU="No se pudo obtener"; VRAM_GB="N/D"; DriverVersion="N/D"; Resolution="N/D" }
    }
}

function Get-RamDetail {
    try {
        $mems = Get-CimInstance Win32_PhysicalMemory
        if (-not $mems) { return [PSCustomObject]@{ Banco="N/D"; Capacidad_GB="N/D"; Tipo="N/D"; Velocidad_MHz="N/D"; Fabricante="N/D"; PartNumber="N/D"; Serial="N/D" } }
        $mems | ForEach-Object {
            [PSCustomObject]@{
                Banco         = Safe-Value $_.BankLabel
                Capacidad_GB  = if ($_.Capacity) { [math]::Round(($_.Capacity / 1GB), 2) } else { "N/D" }
                Tipo          = Safe-Value $_.SMBIOSMemoryType
                Velocidad_MHz = Safe-Value $_.Speed
                Fabricante    = Safe-Value $_.Manufacturer
                PartNumber    = Safe-Value (($_.PartNumber).Trim())
                Serial        = Safe-Value $_.SerialNumber
            }
        }
    } catch {
        [PSCustomObject]@{ Banco="No se pudo obtener"; Capacidad_GB="N/D"; Tipo="N/D"; Velocidad_MHz="N/D"; Fabricante="N/D"; PartNumber="N/D"; Serial="N/D" }
    }
}

function Get-SmartPredictStatusMap {
    $map = @{}
    try {
        $smart = Get-WmiObject -Namespace root\wmi -Class MSStorageDriver_FailurePredictStatus
        foreach ($item in $smart) {
            $map[$item.InstanceName] = [PSCustomObject]@{
                PredictFailure = $item.PredictFailure
                Reason         = $item.Reason
            }
        }
    } catch {}
    return $map
}

function Get-PhysicalDiskMap {
    $map = @{}
    try {
        $physicalDisks = Get-PhysicalDisk
        foreach ($pd in $physicalDisks) {
            if ($pd.FriendlyName) { $map[$pd.FriendlyName] = $pd }
            if ($pd.SerialNumber) { $map[$pd.SerialNumber] = $pd }
        }
    } catch {}
    return $map
}

function Get-DiskHealth {
    try {
        $smartMap = Get-SmartPredictStatusMap
        $physicalMap = Get-PhysicalDiskMap
        $disks = Get-CimInstance Win32_DiskDrive
        if (-not $disks) {
            return [PSCustomObject]@{
                Disco="N/D"; Modelo="No detectado"; Serial="N/D"; Tipo="N/D"; Interface="N/D"; Tamano_GB="N/D"; Estado="SIN DATOS";
                Salud_Windows="N/D"; Estado_Operativo="N/D"; SMART_Fallo="N/D"; SMART_Razon="N/D"; Detalle="No se detectaron discos"
            }
        }
        $results = foreach ($disk in $disks) {
            $model = ($disk.Model -replace '\s+', ' ').Trim()
            $serial = ($disk.SerialNumber -replace '\s+', ' ').Trim()
            $sizeGB = if ($disk.Size) { [math]::Round(($disk.Size / 1GB), 2) } else { "N/D" }
            $matchedPd = $null
            if ($physicalMap.ContainsKey($model)) { $matchedPd = $physicalMap[$model] }
            elseif ($serial -and $physicalMap.ContainsKey($serial)) { $matchedPd = $physicalMap[$serial] }
            else {
                try {
                    $matchedPd = Get-PhysicalDisk | Where-Object {
                        $_.FriendlyName -like "*$model*" -or ($serial -and $_.SerialNumber -like "*$serial*")
                    } | Select-Object -First 1
                } catch {}
            }
            $healthStatus = if ($matchedPd) { $matchedPd.HealthStatus } else { "Unknown" }
            $operational  = if ($matchedPd) { ($matchedPd.OperationalStatus -join ", ") } else { "Unknown" }
            $mediaType    = if ($matchedPd) { $matchedPd.MediaType } else { "Unknown" }
            $predictFailure = $false
            $predictReason  = 0
            foreach ($k in $smartMap.Keys) {
                if ($k -like "*$($disk.PNPDeviceID)*" -or ($serial -and $k -like "*$serial*") -or $k -like "*$model*") {
                    $predictFailure = $smartMap[$k].PredictFailure
                    $predictReason  = $smartMap[$k].Reason
                    break
                }
            }
            $estado = "BIEN"
            $detalle = "Sin alertas criticas detectadas"
            if ($predictFailure -eq $true) {
                $estado = "REEMPLAZAR"; $detalle = "SMART indica fallo predictivo"
            } elseif ($healthStatus -match "Unhealthy|Warning" -or $operational -match "Lost Communication|Failed|Offline|Unhealthy") {
                $estado = "MAL"; $detalle = "Windows reporta problema de salud u operacion"
            } elseif ($healthStatus -eq "Unknown" -and $operational -eq "Unknown") {
                $estado = "SIN DATOS"; $detalle = "El fabricante o controlador no expone salud completa"
            }
            [PSCustomObject]@{
                Disco            = "\\.\PHYSICALDRIVE$($disk.Index)"
                Modelo           = Safe-Value $model
                Serial           = if ($serial) { $serial } else { "N/D" }
                Tipo             = Safe-Value $mediaType
                Interface        = Safe-Value $disk.InterfaceType
                Tamano_GB        = $sizeGB
                Estado           = $estado
                Salud_Windows    = Safe-Value $healthStatus
                Estado_Operativo = Safe-Value $operational
                SMART_Fallo      = if ($predictFailure) { "SI" } else { "NO" }
                SMART_Razon      = $predictReason
                Detalle          = $detalle
            }
        }
        return $results
    } catch {
        return [PSCustomObject]@{
            Disco="N/D"; Modelo="No se pudo obtener"; Serial="N/D"; Tipo="N/D"; Interface="N/D"; Tamano_GB="N/D"; Estado="SIN DATOS";
            Salud_Windows="N/D"; Estado_Operativo="N/D"; SMART_Fallo="N/D"; SMART_Razon="N/D"; Detalle="Error al consultar discos"
        }
    }
}

function Get-VolumeUsage {
    try {
        $vols = Get-Volume | Where-Object { $_.DriveLetter }
        if (-not $vols) { return [PSCustomObject]@{ Unidad="N/D"; Etiqueta="N/D"; FileSystem="N/D"; Tamano_GB="N/D"; Libre_GB="N/D"; Uso_Porcentaje="N/D"; Alerta="N/D" } }
        $vols | ForEach-Object {
            $sizeGB = if ($_.Size) { [math]::Round($_.Size / 1GB, 2) } else { 0 }
            $freeGB = if ($_.SizeRemaining) { [math]::Round($_.SizeRemaining / 1GB, 2) } else { 0 }
            $usedPct = if ($_.Size -gt 0) { [math]::Round((($_.Size - $_.SizeRemaining) / $_.Size) * 100, 2) } else { 0 }
            $alerta = if ($usedPct -ge 95) { "CRITICO" } elseif ($usedPct -ge 90) { "MUY ALTO" } elseif ($usedPct -ge 80) { "ALTO" } else { "OK" }
            [PSCustomObject]@{
                Unidad         = "$($_.DriveLetter):"
                Etiqueta       = Safe-Value $_.FileSystemLabel
                FileSystem     = Safe-Value $_.FileSystem
                Tamano_GB      = $sizeGB
                Libre_GB       = $freeGB
                Uso_Porcentaje = $usedPct
                Alerta         = $alerta
            }
        }
    } catch {
        [PSCustomObject]@{ Unidad="No se pudo obtener"; Etiqueta="N/D"; FileSystem="N/D"; Tamano_GB="N/D"; Libre_GB="N/D"; Uso_Porcentaje="N/D"; Alerta="N/D" }
    }
}

function Get-NetworkInfo {
    try {
        $nets = Get-NetAdapter
        if (-not $nets) { return [PSCustomObject]@{ Nombre="No detectada"; Interface="N/D"; Estado="N/D"; Velocidad="N/D"; MAC="N/D" } }
        $nets | ForEach-Object {
            [PSCustomObject]@{
                Nombre     = Safe-Value $_.Name
                Interface  = Safe-Value $_.InterfaceDescription
                Estado     = Safe-Value $_.Status
                Velocidad  = Safe-Value $_.LinkSpeed
                MAC        = Safe-Value $_.MacAddress
            }
        }
    } catch {
        [PSCustomObject]@{ Nombre="No se pudo obtener"; Interface="N/D"; Estado="N/D"; Velocidad="N/D"; MAC="N/D" }
    }
}

function Get-SecurityChecks {
    try {
        $secureBoot = $null
        try { $secureBoot = Confirm-SecureBootUEFI } catch { $secureBoot = "No soportado o BIOS Legacy" }
        $tpm = Get-Tpm
        $av = Get-CimInstance -Namespace root/SecurityCenter2 -ClassName AntivirusProduct
        [PSCustomObject]@{
            SecureBoot          = Safe-Value $secureBoot
            TPM_Presente        = Safe-Value $tpm.TpmPresent
            TPM_Listo           = Safe-Value $tpm.TpmReady
            TPM_Version         = Safe-Value $tpm.ManufacturerVersion
            AntivirusRegistrado = if ($av) { ($av.displayName -join ", ") } else { "N/D" }
        }
    } catch {
        [PSCustomObject]@{ SecureBoot="No se pudo obtener"; TPM_Presente="N/D"; TPM_Listo="N/D"; TPM_Version="N/D"; AntivirusRegistrado="N/D" }
    }
}

function Get-BatteryInfo {
    try {
        $battery = Get-CimInstance Win32_Battery
        if (-not $battery) { return [PSCustomObject]@{ BateriaDetectada="NO"; Estado="Equipo sin bateria o desktop"; CargaActualPct="N/D"; EstadoBateria="N/D" } }
        $battery | ForEach-Object {
            [PSCustomObject]@{
                BateriaDetectada = "SI"
                Estado           = Safe-Value $_.Status
                CargaActualPct   = Safe-Value $_.EstimatedChargeRemaining
                EstadoBateria    = Safe-Value $_.BatteryStatus
            }
        }
    } catch {
        [PSCustomObject]@{ BateriaDetectada="No se pudo obtener"; Estado="N/D"; CargaActualPct="N/D"; EstadoBateria="N/D" }
    }
}

function Get-CriticalEvents {
    $start = (Get-Date).AddDays(-30)
    $results = @()
    $queries = @(
        @{ LogName = "System"; ProviderName = "Microsoft-Windows-WHEA-Logger"; Levels = @(1,2,3) },
        @{ LogName = "System"; ProviderName = "Disk"; Levels = @(1,2,3) },
        @{ LogName = "System"; ProviderName = "Ntfs"; Levels = @(1,2,3) },
        @{ LogName = "System"; ProviderName = "Microsoft-Windows-Kernel-Power"; Levels = @(1,2,3) },
        @{ LogName = "Application"; ProviderName = "Application Error"; Levels = @(1,2,3) },
        @{ LogName = "System"; ProviderName = "Service Control Manager"; Levels = @(1,2,3) }
    )
    foreach ($q in $queries) {
        foreach ($lvl in $q.Levels) {
            try {
                $ev = Get-WinEvent -FilterHashtable @{
                    LogName      = $q.LogName
                    ProviderName = $q.ProviderName
                    Level        = $lvl
                    StartTime    = $start
                } -ErrorAction SilentlyContinue
                if ($ev) { $results += $ev | Select-Object TimeCreated, Id, ProviderName, LevelDisplayName, Message }
            } catch {}
        }
    }
    if (-not $results -or $results.Count -eq 0) { return [PSCustomObject]@{ TimeCreated=""; Id=""; ProviderName="Sin eventos criticos recientes"; LevelDisplayName=""; Message="" } }
    $results | Sort-Object TimeCreated -Descending | Select-Object -First 50
}

function Get-WarningSummary {
    param($CriticalEvents)
    $items = New-Object System.Collections.Generic.List[object]
    if ($CriticalEvents | Where-Object { $_.ProviderName -eq "Microsoft-Windows-WHEA-Logger" }) {
        $items.Add([PSCustomObject]@{ Tipo="Advertencias de hardware"; Mensaje="Windows detecto eventos de hardware que conviene revisar para evitar fallas futuras." })
    }
    if ($CriticalEvents | Where-Object { $_.ProviderName -eq "Microsoft-Windows-Kernel-Power" }) {
        $items.Add([PSCustomObject]@{ Tipo="Reinicios o apagados inesperados"; Mensaje="Se registraron reinicios o apagados abruptos. Conviene revisar fuente, temperatura o estabilidad general." })
    }
    if ($CriticalEvents | Where-Object { $_.ProviderName -in @("Disk","Ntfs") }) {
        $items.Add([PSCustomObject]@{ Tipo="Advertencias de almacenamiento"; Mensaje="Se encontraron eventos relacionados con disco o sistema de archivos." })
    }
    if ($CriticalEvents | Where-Object { $_.ProviderName -eq "Application Error" }) {
        $items.Add([PSCustomObject]@{ Tipo="Errores de aplicaciones"; Mensaje="Se detectaron cierres o fallas de aplicaciones en Windows." })
    }
    if ($items.Count -eq 0) {
        $items.Add([PSCustomObject]@{ Tipo="Sin alertas fuertes"; Mensaje="No se detectaron warnings o eventos criticos relevantes en el periodo analizado." })
    }
    return $items
}

function Get-WindowsUpdateStatus {
    try {
        $rebootPending = $false
        if (Test-Path "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Component Based Servicing\RebootPending") { $rebootPending = $true }
        if (Test-Path "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\WindowsUpdate\Auto Update\RebootRequired") { $rebootPending = $true }
        $service = Get-Service wuauserv
        [PSCustomObject]@{
            ServicioWindowsUpdate = Safe-Value $service.Status
            ReinicioPendiente     = if ($rebootPending) { "SI" } else { "NO" }
        }
    } catch {
        [PSCustomObject]@{ ServicioWindowsUpdate="No se pudo obtener"; ReinicioPendiente="N/D" }
    }
}

function Get-TrimStatus {
    try {
        $trim = fsutil behavior query DisableDeleteNotify 2>$null
        $estado = "N/D"
        if ($trim -match "DisableDeleteNotify = 0") { $estado = "ACTIVO" }
        elseif ($trim -match "DisableDeleteNotify = 1") { $estado = "DESACTIVADO" }
        [PSCustomObject]@{ TRIM=$estado; Detalle=($trim -join " ") }
    } catch {
        [PSCustomObject]@{ TRIM="No se pudo obtener"; Detalle="N/D" }
    }
}

function Get-BootMetrics {
    try {
        $os = Get-CimInstance Win32_OperatingSystem
        $lastBoot = To-DT $os.LastBootUpTime
        $uptime = (Get-Date) - $lastBoot
        [PSCustomObject]@{
            UltimoArranque = $lastBoot
            Uptime_Horas   = [math]::Round($uptime.TotalHours,2)
            Uptime_Dias    = [math]::Round($uptime.TotalDays,2)
        }
    } catch {
        [PSCustomObject]@{ UltimoArranque="N/D"; Uptime_Horas="N/D"; Uptime_Dias="N/D" }
    }
}

function Get-CurrentPerformance {
    try {
        $cpuSample = (Get-Counter '\Processor(_Total)\% Processor Time').CounterSamples.CookedValue
        $os = Get-CimInstance Win32_OperatingSystem
        $totalMemGB = [math]::Round($os.TotalVisibleMemorySize / 1MB, 2)
        $freeMemGB = [math]::Round($os.FreePhysicalMemory / 1MB, 2)
        $usedMemGB = [math]::Round($totalMemGB - $freeMemGB, 2)
        $usedMemPct = if ($totalMemGB -gt 0) { [math]::Round(($usedMemGB / $totalMemGB) * 100, 2) } else { 0 }
        [PSCustomObject]@{
            CPU_Actual_Pct  = [math]::Round($cpuSample,2)
            RAM_Usada_GB    = $usedMemGB
            RAM_Total_GB    = $totalMemGB
            RAM_Usada_Pct   = $usedMemPct
        }
    } catch {
        [PSCustomObject]@{ CPU_Actual_Pct="N/D"; RAM_Usada_GB="N/D"; RAM_Total_GB="N/D"; RAM_Usada_Pct="N/D" }
    }
}

function Get-TopProcesses {
    try {
        Get-Process | Sort-Object CPU -Descending | Select-Object -First 12 `
            @{N='Proceso';E={$_.ProcessName}},
            @{N='CPU_s';E={[math]::Round($_.CPU,2)}},
            @{N='RAM_MB';E={[math]::Round($_.WorkingSet64 / 1MB,2)}},
            @{N='Id';E={$_.Id}}
    } catch {
        [PSCustomObject]@{ Proceso="No se pudo obtener"; CPU_s="N/D"; RAM_MB="N/D"; Id="N/D" }
    }
}

function Get-StartupApps {
    try {
        $items = Get-CimInstance Win32_StartupCommand | Select-Object `
            @{N='Nombre';E={$_.Name}},
            @{N='Comando';E={$_.Command}},
            @{N='Ubicacion';E={$_.Location}},
            @{N='Usuario';E={$_.User}}
        if (-not $items) { return [PSCustomObject]@{ Nombre="No detectado"; Comando="N/D"; Ubicacion="N/D"; Usuario="N/D" } }
        $items
    } catch {
        [PSCustomObject]@{ Nombre="No se pudo obtener"; Comando="N/D"; Ubicacion="N/D"; Usuario="N/D" }
    }
}

function Get-InstalledApps {
    $paths = @(
        "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*",
        "HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*"
    )
    $items = @()
    foreach ($p in $paths) {
        try {
            $items += Get-ItemProperty $p | Where-Object { $_.DisplayName } | Select-Object `
                @{N='Nombre';E={$_.DisplayName}},
                @{N='Version';E={$_.DisplayVersion}},
                @{N='Publisher';E={$_.Publisher}},
                @{N='Fecha';E={$_.InstallDate}}
        } catch {}
    }
    if (-not $items) {
        return [PSCustomObject]@{ Nombre="No se pudo obtener"; Version="N/D"; Publisher="N/D"; Fecha="N/D" }
    }
    $items | Sort-Object Nombre -Unique
}

function Get-DefenderStatus {
    try {
        $mp = Get-MpComputerStatus
        [PSCustomObject]@{
            Antivirus_Activo             = $mp.AntivirusEnabled
            TiempoReal_Activo            = $mp.RealTimeProtectionEnabled
            Antispyware_Activo           = $mp.AntispywareEnabled
            Motor_Antimalware_Version    = $mp.AMEngineVersion
            Definiciones_Antivirus       = $mp.AntivirusSignatureVersion
            Definiciones_Antispyware     = $mp.AntispywareSignatureVersion
            Ultimo_Update_Firmas         = $mp.AntispywareSignatureLastUpdated
            Ultimo_QuickScan             = $mp.QuickScanEndTime
            Ultimo_FullScan              = $mp.FullScanEndTime
        }
    } catch {
        [PSCustomObject]@{
            Antivirus_Activo="N/D"; TiempoReal_Activo="N/D"; Antispyware_Activo="N/D"; Motor_Antimalware_Version="N/D";
            Definiciones_Antivirus="N/D"; Definiciones_Antispyware="N/D"; Ultimo_Update_Firmas="N/D"; Ultimo_QuickScan="N/D"; Ultimo_FullScan="N/D"
        }
    }
}

function Get-SystemIntegrityStatus {
    $sfcLog = Join-Path $env:windir "Logs\CBS\CBS.log"
    $sfcState = "Sin datos"
    $sfcHint = "Todavia no se ejecuto analisis desde este script"
    try {
        if (Test-Path $sfcLog) {
            $recentSfc = Select-String -Path $sfcLog -Pattern "\[SR\]" | Select-Object -Last 20
            if ($recentSfc) {
                $join = ($recentSfc.Line -join " ")
                if ($join -match "cannot repair member file|could not reproject corrupted file") {
                    $sfcState = "CORRUPCION DETECTADA"; $sfcHint = "Conviene correr SFC y posiblemente DISM"
                } elseif ($join -match "Repairing corrupted file|Verify and Repair Transaction completed") {
                    $sfcState = "REPARACIONES REGISTRADAS"; $sfcHint = "Hubo reparaciones en archivos del sistema"
                } else {
                    $sfcState = "SIN INDICIOS CLAROS"; $sfcHint = "No se encontraron errores claros en los ultimos registros"
                }
            }
        }
    } catch {}
    [PSCustomObject]@{
        Estado_SFC_Logs = $sfcState
        Observacion     = $sfcHint
        Recomendacion   = "Para validar al 100%, correr: sfc /scannow y DISM /Online /Cleanup-Image /RestoreHealth"
    }
}

function Get-HardwareFingerprint {
    param($SystemInfo,$DiskInfo)
    $diskPrincipal = $DiskInfo | Sort-Object Disco | Select-Object -First 1
    $parts = @(
        [string]$env:COMPUTERNAME,
        [string]$SystemInfo.NroSerieEquipo,
        [string]$SystemInfo.Motherboard,
        [string]$SystemInfo.CPU,
        [string]$SystemInfo.RAM_Total_GB,
        [string]$diskPrincipal.Modelo,
        [string]$diskPrincipal.Serial
    )
    $plain = ($parts -join "|")
    $sha = [System.Security.Cryptography.SHA256]::Create()
    $bytes = [System.Text.Encoding]::UTF8.GetBytes($plain)
    $hash = $sha.ComputeHash($bytes)
    $hashString = ([System.BitConverter]::ToString($hash)).Replace("-", "")
    [PSCustomObject]@{
        Fingerprint       = $hashString
        Hostname          = $env:COMPUTERNAME
        Serial_Equipo     = [string]$SystemInfo.NroSerieEquipo
        Motherboard       = [string]$SystemInfo.Motherboard
        CPU               = [string]$SystemInfo.CPU
        RAM_Total_GB      = [string]$SystemInfo.RAM_Total_GB
        Disco_Modelo      = [string]$diskPrincipal.Modelo
        Disco_Serial      = [string]$diskPrincipal.Serial
    }
}

function Get-HardwareAgeAssessment {
    param($SystemInfo,$GpuInfo,$DiskInfo,$RamInfo)
    $cpuModel = [string]$SystemInfo.CPU
    $gpuModel = [string](($GpuInfo | Select-Object -First 1).GPU)
    $ramTotal = 0
    try { $ramTotal = [double]$SystemInfo.RAM_Total_GB } catch {}
    $ramSpeed = 0
    try { $ramSpeed = [int](($RamInfo | Select-Object -First 1).Velocidad_MHz) } catch {}
    $primaryDiskType = [string](($DiskInfo | Select-Object -First 1).Tipo)

    $cpuClass = "INTERMEDIO"; $cpuAdvice = "Aceptable para uso basico"
    if ($cpuModel -match "FX-|A8-|A6-|Phenom|Athlon\(tm\)|Athlon II|Core\(TM\)2|Pentium|Celeron|i3-2|i3-3|i5-2|i5-3|i7-2|i7-3") {
        $cpuClass = "VIEJO"; $cpuAdvice = "Procesador muy viejo. Si la PC se usa para trabajo diario, conviene cambiar plataforma"
    } elseif ($cpuModel -match "Ryzen 1|Ryzen 2|i[3579]-4|i[3579]-5|i[3579]-6|i[3579]-7") {
        $cpuClass = "USABLE"; $cpuAdvice = "Todavia sirve, pero ya no es plataforma nueva"
    } elseif ($cpuModel -match "Ryzen 3 4|Ryzen 5 4|Ryzen 7 4|Ryzen 5 5|Ryzen 7 5|Ryzen 9|i[3579]-10|i[3579]-11|i[3579]-12|i[3579]-13|i[3579]-14|Ultra") {
        $cpuClass = "NUEVO"; $cpuAdvice = "Procesador moderno. No conviene cambiarlo salvo necesidad puntual"
    }

    $ramClass = "INTERMEDIA"; $ramAdvice = "RAM aceptable"
    if ($ramTotal -lt 8) {
        $ramClass = "VIEJA / INSUFICIENTE"; $ramAdvice = "Menos de 8 GB hoy es muy poco. Conviene ampliar urgente"
    } elseif ($ramTotal -lt 16) {
        $ramClass = "USABLE"; $ramAdvice = "8 GB alcanza justo. Para fluidez real, conviene subir a 16 GB"
    } elseif ($ramTotal -lt 32) {
        $ramClass = "BUENA"; $ramAdvice = "16 GB hoy esta bien para la mayoria de los usos"
    } else {
        $ramClass = "NUEVA / SOBRADA"; $ramAdvice = "32 GB o mas. Hoy esta sobrada para la mayoria de los usos"
    }
    if ($ramSpeed -gt 0 -and $ramSpeed -le 1600) { $ramAdvice += ". La velocidad es baja y delata plataforma vieja" }

    $diskClass = "SIN DATOS"; $diskAdvice = "No se pudo clasificar"
    if ($primaryDiskType -match "HDD") {
        $diskClass = "VIEJO"; $diskAdvice = "Si el sistema corre sobre HDD, conviene pasar a SSD"
    } elseif ($primaryDiskType -match "SSD" -or (($DiskInfo | Where-Object {$_.Modelo -match "NVMe|SSD"}))) {
        $diskClass = "ACTUAL"; $diskAdvice = "Tener SSD ayuda mucho. Si sigue lenta, el cuello suele ser CPU o RAM"
    }

    $gpuClass = "INTERMEDIA"; $gpuAdvice = "GPU razonable"
    if ($gpuModel -match "HD 4|HD 5|R5 Graphics|GT 7|GTX 6|GTX 7|GT 1030|Intel\(R\) HD") {
        $gpuClass = "VIEJA"; $gpuAdvice = "Grafica vieja o basica. Sirve para oficina, no para trabajo pesado ni juegos modernos"
    } elseif ($gpuModel -match "RTX 2|RTX 3|RTX 4|RX 6|RX 7|Arc") {
        $gpuClass = "NUEVA / VIGENTE"; $gpuAdvice = "GPU actual o relativamente actual"
    }

    $overall = "EQUIPO USABLE"; $overallAdvice = "No hace falta cambiar todo"
    if ($cpuClass -eq "VIEJO" -and $ramTotal -lt 16) {
        $overall = "PLATAFORMA VIEJA"; $overallAdvice = "Poner solo SSD no alcanza. Conviene evaluar cambio de mother + CPU + RAM"
    } elseif ($cpuClass -eq "USABLE" -and $ramTotal -lt 16) {
        $overall = "MEJORA RECOMENDADA"; $overallAdvice = "Conviene ampliar RAM antes de pensar en cambiar toda la PC"
    } elseif ($cpuClass -eq "NUEVO" -and $diskClass -eq "ACTUAL" -and $ramTotal -ge 16) {
        $overall = "EQUIPO VIGENTE"; $overallAdvice = "No conviene cambiar hardware salvo necesidad puntual"
    }

    [PSCustomObject]@{
        CPU_Estado         = $cpuClass
        CPU_Comentario     = $cpuAdvice
        RAM_Estado         = $ramClass
        RAM_Comentario     = $ramAdvice
        Disco_Estado       = $diskClass
        Disco_Comentario   = $diskAdvice
        GPU_Estado         = $gpuClass
        GPU_Comentario     = $gpuAdvice
        Equipo_Estado      = $overall
        Equipo_Comentario  = $overallAdvice
    }
}

function Get-PCLAFPaths {
    $root = "C:\ProgramData\PCLAF"
    [PSCustomObject]@{
        RootPath    = $root
        LastJson    = (Join-Path $root "last-diagnostic.json")
        CurrentJson = (Join-Path $root "current-diagnostic.json")
    }
}

function Set-PCLAFMark {
    param($Fingerprint,$FinalStatus,$SystemInfo,$DiskInfo,$Tecnico,$SistemaInstaladoPorPCLAF,$MesesMantenimiento)
    $regPath = "HKLM:\SOFTWARE\PCLAF\Diagnostics"
    try {
        if (-not (Test-Path $regPath)) { New-Item -Path $regPath -Force | Out-Null }
        $diskSerials = ($DiskInfo | ForEach-Object { $_.Serial }) -join " | "
        Set-ItemProperty -Path $regPath -Name "LastRunDate" -Value (Get-Date).ToString("s") -Force
        Set-ItemProperty -Path $regPath -Name "ScriptVersion" -Value $ScriptVersion -Force
        Set-ItemProperty -Path $regPath -Name "EstadoGeneral" -Value ([string]$FinalStatus.EstadoGeneral) -Force
        Set-ItemProperty -Path $regPath -Name "Fingerprint" -Value ([string]$Fingerprint.Fingerprint) -Force
        Set-ItemProperty -Path $regPath -Name "Equipo" -Value ([string]$env:COMPUTERNAME) -Force
        Set-ItemProperty -Path $regPath -Name "SerialEquipo" -Value ([string]$SystemInfo.NroSerieEquipo) -Force
        Set-ItemProperty -Path $regPath -Name "CPU" -Value ([string]$SystemInfo.CPU) -Force
        Set-ItemProperty -Path $regPath -Name "RAM_Total_GB" -Value ([string]$SystemInfo.RAM_Total_GB) -Force
        Set-ItemProperty -Path $regPath -Name "DiskSerials" -Value ([string]$diskSerials) -Force
        Set-ItemProperty -Path $regPath -Name "Tecnico" -Value ([string]$Tecnico) -Force
        Set-ItemProperty -Path $regPath -Name "SistemaInstaladoPorPCLAF" -Value ($(if($SistemaInstaladoPorPCLAF){"SI"}else{"NO"})) -Force
        Set-ItemProperty -Path $regPath -Name "MesesMantenimiento" -Value ([string]$MesesMantenimiento) -Force
        return $true
    } catch { return $false }
}

function Read-PCLAFRecord {
    param($Paths)
    try {
        if (Test-Path $Paths.LastJson) {
            return (Get-Content $Paths.LastJson -Raw | ConvertFrom-Json)
        }
    } catch {}
    return $null
}

function Write-PCLAFRecord {
    param($Paths,$RecordObject)
    try {
        if (-not (Test-Path $Paths.RootPath)) { New-Item -Path $Paths.RootPath -ItemType Directory -Force | Out-Null }
        $json = $RecordObject | ConvertTo-Json -Depth 10
        Set-Content -Path $Paths.CurrentJson -Value $json -Encoding UTF8
        Set-Content -Path $Paths.LastJson -Value $json -Encoding UTF8
        return $true
    } catch { return $false }
}

function Compare-PCLAFMark {
    param($PreviousRecord,$Fingerprint,$SystemInfo,$DiskInfo,$GpuInfo)
    $result = [PSCustomObject]@{
        Marca_Previa_Encontrada = "NO"
        Fecha_Ultima_Revision   = "N/D"
        Tecnico_Anterior        = "N/D"
        Sistema_Instalado_Por_PCLAF = "N/D"
        Fingerprint_Anterior    = "N/D"
        Fingerprint_Actual      = $Fingerprint.Fingerprint
        Coincide_Fingerprint    = "N/D"
        Cambio_Disco            = "N/D"
        Cambio_RAM              = "N/D"
        Cambio_CPU              = "N/D"
        Cambio_GPU              = "N/D"
        Observacion             = "No habia marca previa"
    }

    try {
        if ($PreviousRecord) {
            $prevDiskSerials = ""
            try { $prevDiskSerials = (($PreviousRecord.Discos | ForEach-Object { $_.Serial }) -join " | ") } catch {}
            $prevRam = ""
            try { $prevRam = [string]$PreviousRecord.SystemSummary.RAM_Total_GB } catch {}
            $prevCpu = ""
            try { $prevCpu = [string]$PreviousRecord.SystemSummary.CPU } catch {}
            $prevGpu = ""
            try { $prevGpu = [string](($PreviousRecord.GPU | Select-Object -First 1).GPU) } catch {}
            $prevDate = ""
            try { $prevDate = [string]$PreviousRecord.Metadata.Fecha } catch {}
            $prevTecnico = ""
            try { $prevTecnico = [string]$PreviousRecord.Metadata.Tecnico } catch {}
            $prevInst = ""
            try { $prevInst = [string]$PreviousRecord.Metadata.SistemaInstaladoPorPCLAF } catch {}
            $prevFingerprint = ""
            try { $prevFingerprint = [string]$PreviousRecord.Fingerprint.Fingerprint } catch {}
            $currentDiskSerials = ($DiskInfo | ForEach-Object { $_.Serial }) -join " | "
            $currentGpu = [string](($GpuInfo | Select-Object -First 1).GPU)

            $result.Marca_Previa_Encontrada = "SI"
            $result.Fecha_Ultima_Revision = if ($prevDate) { $prevDate } else { "N/D" }
            $result.Tecnico_Anterior = if ($prevTecnico) { $prevTecnico } else { "N/D" }
            $result.Sistema_Instalado_Por_PCLAF = if ($prevInst) { $prevInst } else { "N/D" }
            $result.Fingerprint_Anterior = if ($prevFingerprint) { $prevFingerprint } else { "N/D" }
            $result.Coincide_Fingerprint = if ($prevFingerprint -eq $Fingerprint.Fingerprint) { "SI" } else { "NO" }
            $result.Cambio_Disco = if ($prevDiskSerials -and $prevDiskSerials -ne $currentDiskSerials) { "SI" } else { "NO" }
            $result.Cambio_RAM = if ($prevRam -and $prevRam -ne ([string]$SystemInfo.RAM_Total_GB)) { "SI" } else { "NO" }
            $result.Cambio_CPU = if ($prevCpu -and $prevCpu -ne ([string]$SystemInfo.CPU)) { "SI" } else { "NO" }
            $result.Cambio_GPU = if ($prevGpu -and $prevGpu -ne $currentGpu) { "SI" } else { "NO" }

            $notes = New-Object System.Collections.Generic.List[string]
            if ($result.Coincide_Fingerprint -eq "SI") { $notes.Add("El equipo coincide con la ultima revision") }
            else { $notes.Add("La huella general no coincide con la ultima revision") }
            if ($result.Cambio_Disco -eq "SI") { $notes.Add("Se detecta cambio de disco") }
            if ($result.Cambio_RAM -eq "SI") { $notes.Add("Se detecta cambio de RAM") }
            if ($result.Cambio_CPU -eq "SI") { $notes.Add("Se detecta cambio de CPU o plataforma") }
            if ($result.Cambio_GPU -eq "SI") { $notes.Add("Se detecta cambio de GPU") }
            if ($notes.Count -eq 0) { $notes.Add("No se detectaron cambios relevantes") }
            $result.Observacion = ($notes -join " | ")
        }
    } catch {}
    return $result
}

function Ensure-PCLAFReminderTask {
    param(
        [int]$MesesMantenimiento
    )
    $taskName = "PCLAF Mantenimiento Preventivo"
    $next = (Get-Date).AddMonths($MesesMantenimiento).Date.AddHours(10)
    $cmd = 'powershell.exe -WindowStyle Hidden -Command "Add-Type -AssemblyName PresentationFramework; [System.Windows.MessageBox]::Show(''PCLAF recomienda realizar mantenimiento preventivo. Ya paso el periodo sugerido para revisar limpieza interna, pasta termica y temperaturas.'',''PCLAF Mantenimiento Preventivo'')"'
    try {
        schtasks /Delete /TN "$taskName" /F 1>$null 2>$null | Out-Null
        schtasks /Create /SC MONTHLY /MO $MesesMantenimiento /TN "$taskName" /TR "$cmd" /ST $($next.ToString("HH:mm")) /RL HIGHEST /F 1>$null 2>$null | Out-Null
        return [PSCustomObject]@{
            Tarea_Creada = "SI"
            Nombre       = $taskName
            Frecuencia   = "Cada $MesesMantenimiento meses"
            Observacion  = "Recordatorio de mantenimiento preventivo creado"
        }
    } catch {
        return [PSCustomObject]@{
            Tarea_Creada = "NO"
            Nombre       = $taskName
            Frecuencia   = "Cada $MesesMantenimiento meses"
            Observacion  = "No se pudo crear la tarea programada"
        }
    }
}

function Get-Recommendations {
    param($DiskInfo,$VolumeInfo,$CriticalEvents,$PerfInfo,$HwAge,$Integrity,$Defender,$WarningSummary)
    $items = New-Object System.Collections.Generic.List[object]
    if ($DiskInfo | Where-Object { $_.Estado -eq "REEMPLAZAR" }) {
        $items.Add([PSCustomObject]@{ Prioridad="ALTA"; Recomendacion="Reemplazar disco con fallo predictivo"; Motivo="SMART marco riesgo de falla" })
    }
    if ($DiskInfo | Where-Object { $_.Estado -eq "MAL" }) {
        $items.Add([PSCustomObject]@{ Prioridad="ALTA"; Recomendacion="Revisar salud del disco"; Motivo="Windows reporta warning o problema operativo" })
    }
    if ($VolumeInfo | Where-Object { $_.Alerta -in @("CRITICO","MUY ALTO") }) {
        $items.Add([PSCustomObject]@{ Prioridad="MEDIA"; Recomendacion="Liberar espacio en disco"; Motivo="Poco espacio libre perjudica rendimiento y updates" })
    }
    if ($PerfInfo.RAM_Usada_Pct -ne "N/D" -and [double]$PerfInfo.RAM_Usada_Pct -ge 80) {
        $items.Add([PSCustomObject]@{ Prioridad="MEDIA"; Recomendacion="Revisar consumo de RAM y considerar ampliacion"; Motivo="La RAM esta muy exigida en uso actual" })
    }
    if ($HwAge.Equipo_Estado -eq "PLATAFORMA VIEJA") {
        $items.Add([PSCustomObject]@{ Prioridad="ALTA"; Recomendacion="Evaluar cambio de plataforma completa"; Motivo=$HwAge.Equipo_Comentario })
    } elseif ($HwAge.RAM_Estado -in @("VIEJA / INSUFICIENTE","USABLE")) {
        $items.Add([PSCustomObject]@{ Prioridad="MEDIA"; Recomendacion="Subir RAM"; Motivo=$HwAge.RAM_Comentario })
    }
    if ($CriticalEvents | Where-Object { $_.ProviderName -eq "Microsoft-Windows-WHEA-Logger" -and $_.LevelDisplayName -in @("Warning","Error","Critical") }) {
        $items.Add([PSCustomObject]@{ Prioridad="MEDIA"; Recomendacion="Revisar estabilidad de hardware/PCIe"; Motivo="Hay eventos WHEA en Windows" })
    }
    if ($Integrity.Estado_SFC_Logs -in @("CORRUPCION DETECTADA","REPARACIONES REGISTRADAS")) {
        $items.Add([PSCustomObject]@{ Prioridad="MEDIA"; Recomendacion="Correr SFC y DISM"; Motivo=$Integrity.Observacion })
    }
    if ($Defender.Antivirus_Activo -eq $false -or $Defender.TiempoReal_Activo -eq $false) {
        $items.Add([PSCustomObject]@{ Prioridad="ALTA"; Recomendacion="Activar Windows Defender o revisar antivirus"; Motivo="La proteccion en tiempo real no aparece activa" })
    }
    if ($WarningSummary | Where-Object { $_.Tipo -ne "Sin alertas fuertes" }) {
        $items.Add([PSCustomObject]@{ Prioridad="MEDIA"; Recomendacion="Revision preventiva en PCLAF"; Motivo="Se detectaron advertencias o criticos en Windows" })
    }
    if ($items.Count -eq 0) {
        $items.Add([PSCustomObject]@{ Prioridad="BAJA"; Recomendacion="Sin acciones urgentes"; Motivo="No se detectaron alertas fuertes en este analisis" })
    }
    return $items
}

function Get-FinalAssessment {
    param($DiskInfo,$VolumeInfo,$CriticalEvents,$HwAge)
    $estadoGeneral = "PC SANA"
    $motivos = New-Object System.Collections.Generic.List[string]
    if ($DiskInfo | Where-Object { $_.Estado -eq "REEMPLAZAR" }) {
        $estadoGeneral = "REQUIERE REEMPLAZO"; $motivos.Add("Hay un disco con riesgo de falla")
    } elseif ($DiskInfo | Where-Object { $_.Estado -eq "MAL" }) {
        $estadoGeneral = "REQUIERE SERVICE"; $motivos.Add("Hay un disco con problemas")
    }
    if ($VolumeInfo | Where-Object { $_.Alerta -in @("CRITICO","MUY ALTO") }) {
        if ($estadoGeneral -eq "PC SANA") { $estadoGeneral = "APTA CON OBSERVACIONES" }
        $motivos.Add("Hay poco espacio libre")
    }
    $relevantEvents = $CriticalEvents | Where-Object { $_.LevelDisplayName -in @("Warning","Error","Critical") }
    if ($relevantEvents) {
        if ($estadoGeneral -eq "PC SANA") { $estadoGeneral = "APTA CON OBSERVACIONES" }
        $motivos.Add("Se detectaron advertencias o criticos en Windows")
    }
    if ($HwAge.Equipo_Estado -eq "PLATAFORMA VIEJA") {
        if ($estadoGeneral -eq "PC SANA") { $estadoGeneral = "APTA CON OBSERVACIONES" }
        $motivos.Add("La plataforma ya es vieja comparada con hardware actual")
    }
    if ($motivos.Count -eq 0) { $motivos.Add("No se detectaron alertas fuertes") }
    [PSCustomObject]@{
        EstadoGeneral = $estadoGeneral
        Motivos       = ($motivos -join " | ")
    }
}

function Convert-DataTableHtml {
    param([string]$Title, $Data)
    if (-not $Data) { return "<h2>$Title</h2><p>Sin datos</p>" }
    $fragment = $Data | ConvertTo-Html -Fragment -PreContent "<h2>$Title</h2>"
    $html = "<div class='table-wrap'>" + ($fragment -join "`n") + "</div>"
    $html = $html -replace '<td>BIEN</td>', '<td><span class="ok">BIEN</span></td>'
    $html = $html -replace '<td>ACTUAL</td>', '<td><span class="ok">ACTUAL</span></td>'
    $html = $html -replace '<td>NUEVO</td>', '<td><span class="ok">NUEVO</span></td>'
    $html = $html -replace '<td>NUEVA / VIGENTE</td>', '<td><span class="ok">NUEVA / VIGENTE</span></td>'
    $html = $html -replace '<td>NUEVA / SOBRADA</td>', '<td><span class="ok">NUEVA / SOBRADA</span></td>'
    $html = $html -replace '<td>BUENA</td>', '<td><span class="ok">BUENA</span></td>'
    $html = $html -replace '<td>MAL</td>', '<td><span class="warn">MAL</span></td>'
    $html = $html -replace '<td>USABLE</td>', '<td><span class="warn">USABLE</span></td>'
    $html = $html -replace '<td>ALTO</td>', '<td><span class="warn">ALTO</span></td>'
    $html = $html -replace '<td>MUY ALTO</td>', '<td><span class="bad">MUY ALTO</span></td>'
    $html = $html -replace '<td>CRITICO</td>', '<td><span class="bad">CRITICO</span></td>'
    $html = $html -replace '<td>VIEJO</td>', '<td><span class="bad">VIEJO</span></td>'
    $html = $html -replace '<td>VIEJA / INSUFICIENTE</td>', '<td><span class="bad">VIEJA / INSUFICIENTE</span></td>'
    $html = $html -replace '<td>PLATAFORMA VIEJA</td>', '<td><span class="bad">PLATAFORMA VIEJA</span></td>'
    $html = $html -replace '<td>REEMPLAZAR</td>', '<td><span class="bad">REEMPLAZAR</span></td>'
    return $html
}

Update-Stage 5 "Relevando sistema y hardware"
$osInfo        = Get-OsInfo
$systemInfo    = Get-SystemSummary
$gpuInfo       = Get-GpuInfo
$ramInfo       = Get-RamDetail

Update-Stage 20 "Analizando discos y almacenamiento"
$diskInfo      = Get-DiskHealth
$volumeInfo    = Get-VolumeUsage
$trimStatus    = Get-TrimStatus
$bootInfo      = Get-BootMetrics

Update-Stage 35 "Revisando red, seguridad y eventos de Windows"
$networkInfo   = Get-NetworkInfo
$security      = Get-SecurityChecks
$batteryInfo   = Get-BatteryInfo
$criticalEvts  = Get-CriticalEvents
$warningSummary= Get-WarningSummary -CriticalEvents $criticalEvts
$wuStatus      = Get-WindowsUpdateStatus
$defender      = Get-DefenderStatus
$integrity     = Get-SystemIntegrityStatus

Update-Stage 50 "Midiendo rendimiento, procesos y software"
$perfInfo      = Get-CurrentPerformance
$topProcesses  = Get-TopProcesses
$startupApps   = Get-StartupApps
$installedApps = Get-InstalledApps

Update-Stage 65 "Leyendo marca previa y comparando equipo"
$pclafPaths    = Get-PCLAFPaths
$previousRecord= Read-PCLAFRecord -Paths $pclafPaths
$fingerprint   = Get-HardwareFingerprint -SystemInfo $systemInfo -DiskInfo $diskInfo
$hardwareAge   = Get-HardwareAgeAssessment -SystemInfo $systemInfo -GpuInfo $gpuInfo -DiskInfo $diskInfo -RamInfo $ramInfo
$comparison    = Compare-PCLAFMark -PreviousRecord $previousRecord -Fingerprint $fingerprint -SystemInfo $systemInfo -DiskInfo $diskInfo -GpuInfo $gpuInfo

Update-Stage 78 "Calculando recomendaciones y mantenimiento"
$finalStatus   = Get-FinalAssessment -DiskInfo $diskInfo -VolumeInfo $volumeInfo -CriticalEvents $criticalEvts -HwAge $hardwareAge
$recommendations = Get-Recommendations -DiskInfo $diskInfo -VolumeInfo $volumeInfo -CriticalEvents $criticalEvts -PerfInfo $perfInfo -HwAge $hardwareAge -Integrity $integrity -Defender $defender -WarningSummary $warningSummary
$maintenanceTask = Ensure-PCLAFReminderTask -MesesMantenimiento $MesesMantenimiento

Update-Stage 88 "Guardando marca PCLAF"
$record = [PSCustomObject]@{
    Metadata = [PSCustomObject]@{
        Fecha                      = (Get-Date).ToString("s")
        ScriptVersion              = $ScriptVersion
        Equipo                     = $env:COMPUTERNAME
        Tecnico                    = $Tecnico
        SistemaInstaladoPorPCLAF   = $(if($SistemaInstaladoPorPCLAF){"SI"}else{"NO"})
        MesesMantenimiento         = $MesesMantenimiento
        Modo                       = $Modo
    }
    FinalStatus      = $finalStatus
    Fingerprint      = $fingerprint
    Comparacion      = $comparison
    SystemInfo       = $osInfo
    SystemSummary    = $systemInfo
    GPU              = $gpuInfo
    RAM              = $ramInfo
    Discos           = $diskInfo
    Volumenes        = $volumeInfo
    Rendimiento      = $perfInfo
    Arranque         = $bootInfo
    TRIM             = $trimStatus
    Bateria          = $batteryInfo
    Red              = $networkInfo
    Seguridad        = $security
    Defender         = $defender
    Integridad       = $integrity
    WindowsUpdate    = $wuStatus
    WarningSummary   = $warningSummary
    EventosCriticos  = $criticalEvts
    TopProcesos      = $topProcesses
    Inicio           = $startupApps
    InstalledApps    = $installedApps
    HardwareAge      = $hardwareAge
    Recomendaciones  = $recommendations
    Mantenimiento    = $maintenanceTask
}

$markOk = Set-PCLAFMark -Fingerprint $fingerprint -FinalStatus $finalStatus -SystemInfo $systemInfo -DiskInfo $diskInfo -Tecnico $Tecnico -SistemaInstaladoPorPCLAF:$SistemaInstaladoPorPCLAF -MesesMantenimiento $MesesMantenimiento
$writeOk = Write-PCLAFRecord -Paths $pclafPaths -RecordObject $record

Update-Stage 95 "Generando reporte HTML"
$reportHtmlPath = Join-Path $BasePath ("Reporte_" + $Modo + "_" + $env:COMPUTERNAME + "_" + $FechaReporte + ".html")

$style = @"
<style>
:root{--bg:#050505;--panel:#0c0c0c;--panel2:#121212;--line:#252525;--txt:#f5f5f5;--muted:#b9b9b9;--red:#e10600;--red2:#ff2a1f;--ok:#4ade80;--warn:#facc15;--bad:#f87171;}
*{box-sizing:border-box}
html,body{max-width:100%;overflow-x:hidden}
body{margin:0;font-family:Arial,Helvetica,sans-serif;background:radial-gradient(circle at top left, rgba(225,6,0,.10), transparent 25%), linear-gradient(180deg,#020202 0%,#070707 100%);color:var(--txt)}
.container{max-width:1440px;margin:0 auto;padding:24px;width:100%}
.hero{background:linear-gradient(180deg,rgba(255,255,255,.02),rgba(255,255,255,.01));border:1px solid var(--line);border-radius:20px;padding:24px;box-shadow:0 0 24px rgba(0,0,0,.35)}
.brand{display:flex;align-items:center;gap:16px;margin-bottom:16px;min-width:0}
.brand img{width:74px;height:74px;border-radius:14px;display:block;object-fit:cover}
.brand-meta{display:flex;flex-direction:column;min-width:0}
.brand-name{font-size:34px;font-weight:900;letter-spacing:1px;word-break:break-word}
.brand-name .p1{color:#fff}.brand-name .p2{color:var(--red2)}
.brand-sub{font-size:12px;color:var(--muted);text-transform:uppercase;letter-spacing:2px;word-break:break-word}
h1{margin:10px 0 8px;font-size:30px;word-break:break-word}
.subtitle{color:var(--muted);margin:0 0 12px;word-break:break-word}
.kpis{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:14px;margin-top:20px}
.kpi{background:var(--panel2);border:1px solid var(--line);border-radius:14px;padding:14px;min-width:0}
.kpi .l{font-size:12px;text-transform:uppercase;color:var(--muted);margin-bottom:6px}
.kpi .v{font-size:17px;font-weight:800;word-break:break-word;overflow-wrap:anywhere}
.box{background:var(--panel);border:1px solid var(--line);border-radius:16px;padding:18px;margin-top:18px;word-break:break-word}
.banner{margin-top:18px;display:inline-block;padding:12px 16px;border-radius:12px;font-weight:900;letter-spacing:1px;text-transform:uppercase;max-width:100%;word-break:break-word}
.banner.ok{background:rgba(74,222,128,.12);border:1px solid rgba(74,222,128,.35)}
.banner.warn{background:rgba(250,204,21,.12);border:1px solid rgba(250,204,21,.35)}
.banner.bad{background:rgba(248,113,113,.12);border:1px solid rgba(248,113,113,.35)}
h2{margin:28px 0 12px;padding:12px 14px;border-left:4px solid var(--red);border-radius:10px;color:#fff;background:linear-gradient(90deg,rgba(225,6,0,.16),rgba(225,6,0,.04));word-break:break-word}
.table-wrap{width:100%;max-width:100%;overflow-x:auto}
table{width:100%;max-width:100%;border-collapse:collapse;background:var(--panel);border:1px solid var(--line);border-radius:14px;overflow:hidden;margin-bottom:22px;table-layout:fixed}
th,td{border:1px solid var(--line);padding:10px 12px;text-align:left;vertical-align:top;font-size:14px;word-break:break-word;overflow-wrap:anywhere;white-space:normal}
th{background:#141414;color:#fff}
tr:nth-child(even) td{background:#101010}
tr:nth-child(odd) td{background:#0b0b0b}
.ok{color:var(--ok);font-weight:800}.warn{color:var(--warn);font-weight:800}.bad{color:var(--bad);font-weight:800}
.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:14px}
.card{background:var(--panel);border:1px solid var(--line);border-radius:16px;padding:16px;min-width:0}
.card h3{margin:0 0 8px;font-size:16px;word-break:break-word}
.card p{margin:0;color:var(--muted);line-height:1.45;word-break:break-word}
.footer{margin:30px 0 10px;color:var(--muted);font-size:12px;text-align:center}
@media (max-width:900px){.container{padding:14px}.hero{padding:16px}.brand{align-items:flex-start}.brand img{width:60px;height:60px}.brand-name{font-size:28px}h1{font-size:24px}.kpis,.cards{grid-template-columns:1fr}th,td{font-size:12px;padding:8px}}
</style>
"@

$estadoClass = switch ($finalStatus.EstadoGeneral) {
    "PC SANA" { "ok" }
    "APTA CON OBSERVACIONES" { "warn" }
    default { "bad" }
}

$htmlParts = @()
$htmlParts += "<html><head><meta charset='UTF-8'><title>Reporte Diagnostico PCLAF</title>$style</head><body><div class='container'>"
$htmlParts += "<div class='hero'>"
$htmlParts += "<div class='brand'><img src='data:image/png;base64,$LogoBase64' alt='PCLAF Logo'><div class='brand-meta'><div class='brand-name'><span class='p1'>PC</span> <span class='p2'>LAF</span></div><div class='brand-sub'>Servicio Tecnico · Floresta, CABA</div></div></div>"
$htmlParts += "<h1>Reporte de Diagnostico - $($env:COMPUTERNAME)</h1>"
$htmlParts += "<p class='subtitle'>Analisis tecnico local generado por PCLAF</p>"
$htmlParts += "<div class='kpis'>"
$htmlParts += "<div class='kpi'><div class='l'>Fecha</div><div class='v'>$(Get-Date)</div></div>"
$htmlParts += "<div class='kpi'><div class='l'>Modo</div><div class='v'>$Modo</div></div>"
$htmlParts += "<div class='kpi'><div class='l'>Estado general</div><div class='v'><span class='$estadoClass'>$($finalStatus.EstadoGeneral)</span></div></div>"
$htmlParts += "<div class='kpi'><div class='l'>Estado hardware</div><div class='v'>$($hardwareAge.Equipo_Estado)</div></div>"
$htmlParts += "</div>"
$htmlParts += "<div class='banner $estadoClass'>$($finalStatus.EstadoGeneral)</div>"
$htmlParts += "<div class='box'><strong>Motivos:</strong> $($finalStatus.Motivos)</div>"
$htmlParts += "</div>"

$htmlParts += "<h2>Resumen comercial PCLAF</h2>"
$htmlParts += "<div class='cards'>"
$htmlParts += "<div class='card'><h3>Estado del equipo</h3><p>$($hardwareAge.Equipo_Comentario)</p></div>"
$htmlParts += "<div class='card'><h3>Procesador</h3><p><strong>$($hardwareAge.CPU_Estado)</strong><br>$($hardwareAge.CPU_Comentario)</p></div>"
$htmlParts += "<div class='card'><h3>Memoria RAM</h3><p><strong>$($hardwareAge.RAM_Estado)</strong><br>$($hardwareAge.RAM_Comentario)</p></div>"
$htmlParts += "<div class='card'><h3>Almacenamiento</h3><p><strong>$($hardwareAge.Disco_Estado)</strong><br>$($hardwareAge.Disco_Comentario)</p></div>"
$htmlParts += "</div>"

$htmlParts += Convert-DataTableHtml -Title "Advertencias importantes" -Data $warningSummary
$htmlParts += Convert-DataTableHtml -Title "Recomendaciones PCLAF" -Data $recommendations
$htmlParts += Convert-DataTableHtml -Title "Comparativa de Hardware" -Data @($hardwareAge)
$htmlParts += Convert-DataTableHtml -Title "Sistema Operativo" -Data @($osInfo)
$htmlParts += Convert-DataTableHtml -Title "Resumen de Hardware" -Data @($systemInfo)
$htmlParts += Convert-DataTableHtml -Title "GPU" -Data $gpuInfo
$htmlParts += Convert-DataTableHtml -Title "Memoria RAM" -Data $ramInfo
$htmlParts += Convert-DataTableHtml -Title "Estado de Discos" -Data $diskInfo
$htmlParts += Convert-DataTableHtml -Title "Ocupacion de Unidades" -Data $volumeInfo
$htmlParts += Convert-DataTableHtml -Title "Rendimiento Actual" -Data @($perfInfo)
$htmlParts += Convert-DataTableHtml -Title "Mantenimiento preventivo" -Data @($maintenanceTask)

if ($Modo -eq "tecnico") {
    $htmlParts += Convert-DataTableHtml -Title "Historial y marca PCLAF" -Data @($comparison)
    $htmlParts += Convert-DataTableHtml -Title "Fingerprint del equipo" -Data @($fingerprint)
    $htmlParts += Convert-DataTableHtml -Title "Bateria" -Data $batteryInfo
    $htmlParts += Convert-DataTableHtml -Title "Red" -Data $networkInfo
    $htmlParts += Convert-DataTableHtml -Title "Seguridad Basica" -Data @($security)
    $htmlParts += Convert-DataTableHtml -Title "Microsoft Defender" -Data @($defender)
    $htmlParts += Convert-DataTableHtml -Title "Integridad del Sistema" -Data @($integrity)
    $htmlParts += Convert-DataTableHtml -Title "Windows Update" -Data @($wuStatus)
    $htmlParts += Convert-DataTableHtml -Title "Metricas de Arranque" -Data @($bootInfo)
    $htmlParts += Convert-DataTableHtml -Title "TRIM" -Data @($trimStatus)
    $htmlParts += Convert-DataTableHtml -Title "Top Procesos" -Data $topProcesses
    $htmlParts += Convert-DataTableHtml -Title "Programas de Inicio" -Data $startupApps
    $htmlParts += Convert-DataTableHtml -Title "Aplicaciones instaladas" -Data $installedApps
    $htmlParts += Convert-DataTableHtml -Title "Warnings / Error / Critical del visor" -Data $criticalEvts
    $htmlParts += "<div class='box'><strong>Marca PCLAF local:</strong> " + ($(if($markOk){"OK"}else{"NO"})) + "<br><strong>Registro interno actualizado:</strong> " + ($(if($writeOk){"OK"}else{"NO"})) + "<br><strong>Tecnico:</strong> $Tecnico<br><strong>Sistema instalado por PCLAF:</strong> " + ($(if($SistemaInstaladoPorPCLAF){"SI"}else{"NO"})) + "</div>"
} else {
    $htmlParts += "<div class='box'><strong>Tecnico responsable:</strong> $Tecnico<br><strong>Control preventivo sugerido:</strong> cada $MesesMantenimiento meses</div>"
}

$htmlParts += "<div class='footer'>PCLAF · Diagnostico tecnico automatizado</div>"
$htmlParts += "</div></body></html>"

$htmlParts -join "`n" | Set-Content -Path $reportHtmlPath -Encoding UTF8

Update-Stage 100 "Finalizado"
Write-Progress -Activity "PCLAF Diagnostico" -Completed
Write-Host ""
Write-Host "Reporte HTML guardado en: $reportHtmlPath" -ForegroundColor Cyan
Write-Host "Marca PCLAF local: " -NoNewline
if ($markOk) { Write-Host "OK" -ForegroundColor Green } else { Write-Host "NO" -ForegroundColor Yellow }
Write-Host "Modo ejecutado: $Modo" -ForegroundColor DarkGray
